| channel_url           = 
| channel_direct_url    = 

| channel_name2         = 
| channel_url2          = 
| channel_direct_url2   = 

| channel_name3         = 
| channel_url3          = 
| channel_direct_url3   = 

| channel_display_name  = 
| channel_display_name2 = 
| channel_display_name3 = 
| channels              = 
| creator               = 
| presenter             = 
| location              = 
| years_active          = 
| genre                 = 
| subscribers           = 
| subscriber_date       = 
| views                 = 
| view_date             = 
| network               = 
| language              = 
| associated_acts       = 
| channel_website       = 
| silver_year           = 
| silver_button         = 
| gold_year             = 
| gold_button           = 
| diamond_year          = 
| diamond_button        = 
| ruby_year             = 
| ruby_button           = 
| red_diamond_year      = 
| red_diamond_button    = 
| module                = 
| stats_update          = 
| extra_information     = 
}}
</syntaxhighlight>
{{Clear}}

== Examples ==

=== Individual ===
{{Infobox YouTube personality
| name               = Fuslie
| image              = Fuslie TwitchCon 2022 (cropped).jpg
| caption            = Fuslie in 2022
| birth_name         = Leslie Ann Fu
| birth_date         = {{birth date and age|1992|11|23}}
| birth_place        = [[San Francisco Bay Area]], [[California]], U.S.
| education          = [[University of California, Irvine]] ([[Bachelor of Science|BS]])
| occupation         = {{flatlist|
* [[Live streamer]]
* [[YouTuber]]
}}
| organization       = [[100 Thieves]]
| website            = {{URL|fuslie.com}}
| years_active       = 2015–present
| channel_direct_url = fuslie
| genre              = {{flatlist|
* [[Video game|Gaming]]
* [[vlog]]
}}
| subscribers        = 787,000
| views              = 165.9 million
| associated_acts    = {{flatlist|
* [[OfflineTV]]
* [[Valkyrae]]
* [[Sykkuno]]
}}
| silver_year        = 2019
| module             =
  {{Infobox Twitch streamer | subbox=yes
  | years_active     = 2015–2022
  | channel_name     = fuslie
  | genre            = Gaming
  }}
| stats_update       = April 2, 2023
}}

